using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public sealed class ChargeAsyncTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    [TestMethod]
    public async Task ValidCharge_ReturnsSuccessWithChargeId()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ZeroAmount_Fails()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task NegativeAmount_Fails()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", -10m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task NullCardToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(null!, 25m));
    }

    [TestMethod]
    public async Task EmptyCardToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("", 25m));
    }

    [TestMethod]
    public async Task WhitespaceCardToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("   ", 25m));
    }

    [TestMethod]
    public async Task LargeAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 999_999.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task SmallestValidAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0.01m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task MultipleCharges_ReturnDistinctChargeIds()
    {
        var r1 = await _gateway.ChargeAsync("tok_visa_1", 10m);
        var r2 = await _gateway.ChargeAsync("tok_visa_2", 20m);

        Assert.AreNotEqual(r1.ChargeId, r2.ChargeId);
    }
}

[TestClass]
public sealed class RefundAsyncTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    [TestMethod]
    public async Task ValidChargeId_ReturnsSuccessWithRefundId()
    {
        var result = await _gateway.RefundAsync("ch_valid_123");

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.RefundId));
    }

    [TestMethod]
    public async Task NullChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(null!));
    }

    [TestMethod]
    public async Task EmptyChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(""));
    }

    [TestMethod]
    public async Task WhitespaceChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync("   "));
    }

    [TestMethod]
    public async Task NonExistentChargeId_Fails()
    {
        var result = await _gateway.RefundAsync("ch_does_not_exist");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
